module RefModule (
  input [7:0] data_in,
  input control,
  output reg parity
);

  integer obf_i;
  reg [7:0] data_temp;

  always @ (data_in, control) begin
    if (control == 0) begin
      parity <= 0;
    end else begin
      data_temp = data_in;
      parity = 0;
      for (obf_i = 0; obf_i < 8; obf_i = obf_i + 1) begin
        parity = parity ^ data_temp[obf_i];
      end
    end
  end

endmodule
